115→        public val IGNORE_BACKTICKED_IDENTIFIER_PROPERTY: EditorConfigProperty<Boolean> =
116→            EditorConfigProperty(
117→                type =
118→                    PropertyType.LowerCasingPropertyType(
119→                        "ktlint_ignore_back_ticked_identifier",
120→                        "Defines whether the backticked identifier (``) should be ignored",
121→                        PropertyType.PropertyValueParser.BOOLEAN_VALUE_PARSER,
122→                        setOf(true.toString(), false.toString()),
123→                    ),
124→                defaultValue = false,
125→            )
126→    }
